| MCP:6vSAY9 |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:6vSAY9 |     
| MCP:6vSAY9 |     dependencyManagement {
| MCP:6vSAY9 |         imports {
| MCP:6vSAY9 |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:6vSAY9 |         }
| MCP:6vSAY9 |     }
| MCP:6vSAY9 | 
