| MCP:6vSAY9 |                         testTask.configure {
| MCP:6vSAY9 |                             group = 'verification'
| MCP:6vSAY9 |                             useJUnitPlatform {
| MCP:6vSAY9 |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:6vSAY9 |                             }
| MCP:6vSAY9 |                         }
