| MCP:6vSAY9 |             }
| MCP:6vSAY9 |         }
| MCP:6vSAY9 |     }
| MCP:6vSAY9 | 
| MCP:6vSAY9 |     tasks.named('asciidoctor').configure {
| MCP:6vSAY9 |         dependsOn restDocsTest
| MCP:6vSAY9 |     }
| MCP:6vSAY9 | }

| MCP:6vSAY9 | dependencies {
